INSERT INTO `Question` (`id`, `subject`, `type`, `prompt`, `explanation`, `difficulty`, `tagsJson`, `mediaJson`, `gradingType`, `gradingRulesJson`, `createdAt`, `updatedAt`) VALUES
  ('seed_test_01_q01', 'Akhlaq', 'SHORT_TEXT', 'Что означает слово «ахлак» в начале введения?', 'Автор объясняет ахлак как понятие, связанное с природным складом, характером и нравом человека.\n\nSource: Ахлак, множественное число от слова хулук, означает природный склад, характер, нрав', 1, '["imported","akhlaq","test-1","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"природный склад, характер, нрав","answers":["природный склад","характер","нрав","характер и нрав"],"required":["характер"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Ахлак, множественное число от слова хулук, означает природный склад, характер, нрав","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q02', 'Akhlaq', 'SHORT_TEXT', 'Каким словом в тексте названа духовная и нравственная сторона человека?', 'Физическая сторона названа халк, а духовная и нравственная сторона — хулук.\n\nSource: его духовная и нравственная сторона ... называется хулук', 1, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"хулук","answers":["хулук","хулюк"],"required":["хул"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"его духовная и нравственная сторона ... называется хулук","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q03', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: по словам Ибн Аббаса, «здание Ислама» — это ________.', 'В тексте нравственность названа основанием и строением Ислама, подчёркивая её центральное значение.\n\nSource: А здание Ислама — это прекрасная нравственность', 1, '["imported","akhlaq","test-1","fill_blank"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"прекрасная нравственность","answers":["прекрасная нравственность","добрый нрав","благой нрав","нравственность"],"required":["нрав"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"А здание Ислама — это прекрасная нравственность","sourceQuestionType":"fill_blank","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q04', 'Akhlaq', 'SHORT_TEXT', 'Как Хасан аль-Басри определял прекрасную нравственность?', 'Определение Хасана аль-Басри делает акцент на доброжелательности и ненанесении вреда людям.\n\nSource: определял прекрасную нравственность как приветливость и отказ причинять людям вред', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"приветливость и отказ причинять вред","answers":["приветливость и отказ причинять вред","приветливость и не причинять вред","отказ причинять людям вред","приветливость"],"required":["приветлив","вред"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"определял прекрасную нравственность как приветливость и отказ причинять людям вред","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q05', 'Akhlaq', 'SHORT_TEXT', 'Между какими двумя состояниями, по тексту, колеблется человек?', 'Автор описывает человека как существо, способное как пасть ниже низшего, так и подняться к высочайшим степеням.\n\nSource: человек находится в состоянии колебания между асфал-и сафилин и аля-и иллийин', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"между асфал-и сафилин и аля-и иллийин","answers":["асфал-и сафилин и аля-и иллийин","низшее из низших и высочайшие степени","асфал-и сафилин — аля-и иллийин"],"required":["асфал","иллий"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"человек находится в состоянии колебания между асфал-и сафилин и аля-и иллийин","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q06', 'Akhlaq', 'SHORT_TEXT', 'Какие два основных источника исламской нравственности названы прежде всего?', 'Автор связывает исламскую нравственность прежде всего с Кораном и достоверной Сунной.\n\nSource: Основные источники исламской нравственности — прежде всего Коран и достоверная Сунна', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"Коран и достоверная Сунна","answers":["Коран и Сунна","Коран и достоверная Сунна","Священный Коран и Сунна","Книга и Сунна"],"required":["коран","сунн"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Основные источники исламской нравственности — прежде всего Коран и достоверная Сунна","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q07', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: когда Аишу спросили о нраве Пророка, она ответила: «Его нравом был ________».', 'Ответ Аиши подчёркивает связь пророческого нрава с Кораном.\n\nSource: она ответила: «Его нравом был Коран»', 1, '["imported","akhlaq","test-1","fill_blank"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"Коран","answers":["Коран","Священный Коран"],"required":["коран"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"она ответила: «Его нравом был Коран»","sourceQuestionType":"fill_blank","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q08', 'Akhlaq', 'SHORT_TEXT', 'Какую силу автор называет одной из важнейших сил, поддерживающих общество?', 'Введение подчёркивает общественную роль нравственности как силы, удерживающей общество от разложения.\n\nSource: Одна из важнейших сил, поддерживающих общество ... это, несомненно, нравственность', 1, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"нравственность","answers":["нравственность","прекрасная нравственность","мораль","нрав"],"required":["нрав"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Одна из важнейших сил, поддерживающих общество ... это, несомненно, нравственность","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q09', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: в суре «Аль-Фуркан» особые рабы Милостивого ходят по земле ________.', 'Пример особых рабов Милостивого показывает нравственную черту смиренного поведения.\n\nSource: Особые рабы Милостивого — это те, кто ходит по земле смиренно', 1, '["imported","akhlaq","test-1","fill_blank"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"смиренно","answers":["смиренно","со смирением","скромно"],"required":["смир"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Особые рабы Милостивого — это те, кто ходит по земле смиренно","sourceQuestionType":"fill_blank","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q10', 'Akhlaq', 'SHORT_TEXT', 'Что названо важнейшим источником дурной нравственности?', 'В разделе об источнике дурной нравственности автор прямо называет неверие и лицемерие её важнейшим источником.\n\nSource: Важнейший же источник дурной нравственности — неверие и лицемерие', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"неверие и лицемерие","answers":["неверие и лицемерие","куфр и лицемерие","неверие","лицемерие"],"required":["невер","лицемер"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Важнейший же источник дурной нравственности — неверие и лицемерие","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q11', 'Akhlaq', 'TRUE_FALSE', 'Верно или неверно: отсутствие стремления к развитию названо одним из источников дурной нравственности.', 'Автор связывает нравственное истощение с топтанием на месте и довольством уже имеющимся.\n\nSource: Одним из источников дурной нравственности является отсутствие стремления к развитию', 1, '["imported","akhlaq","test-1","true_false"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"верно","answers":["верно","да","правда","истинно"],"required":["верн"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Одним из источников дурной нравственности является отсутствие стремления к развитию","sourceQuestionType":"true_false","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q12', 'Akhlaq', 'SHORT_TEXT', 'Какое имя Аллаха автор связывает с чистотой, опрятностью, порядком и строем во вселенной?', 'Текст объясняет проявления имени Куддус через чистоту, устройство и порядок в мире.\n\nSource: Вся чистота, опрятность, совершенное устройство, порядок и строй ... суть проявления имени Куддус', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"Куддус","answers":["Куддус","аль-Куддус","имя Куддус"],"required":["куддус"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Вся чистота, опрятность, совершенное устройство, порядок и строй ... суть проявления имени Куддус","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q13', 'Akhlaq', 'SHORT_TEXT', 'Какие три основные силы в человеке перечисляют исламские нравоведы?', 'Раздел о сират аль-мустаким объясняет нравственную умеренность через три силы человеческой природы.\n\nSource: они называли силой разума ... силой гнева ... силой страсти', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"сила разума, сила гнева и сила страсти","answers":["разум, гнев и страсть","сила разума, сила гнева и сила страсти","разумная сила, сила гнева, сила страсти"],"required":["разум","гнев","страст"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"они называли силой разума ... силой гнева ... силой страсти","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q14', 'Akhlaq', 'SHORT_TEXT', 'Как называется умеренное состояние разумной силы?', 'Умеренность разума состоит в способности видеть вещи такими, каковы они есть, и ставить всё на своё место.\n\nSource: её умеренное состояние ... издавна именуется мудростью', 2, '["imported","akhlaq","test-1","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"мудрость","answers":["мудрость","хикма"],"required":["мудр"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"её умеренное состояние ... издавна именуется мудростью","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q15', 'Akhlaq', 'SHORT_TEXT', 'Как называется срединное состояние силы гнева между дерзостью и трусостью?', 'Текст называет шаджаат мужественной стойкостью, свободной от паники и безрассудства.\n\nSource: В середине между этими двумя крайностями находится шаджаат', 2, '["imported","akhlaq","test-1","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"шаджаат, мужество","answers":["шаджаат","мужество","мужественная стойкость"],"required":["мужеств"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"В середине между этими двумя крайностями находится шаджаат","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q16', 'Akhlaq', 'SHORT_TEXT', 'Как называется умеренное состояние силы вожделения?', 'Целомудрие описано как сохранение дозволенных границ при контроле телесных желаний.\n\nSource: положение же прямоты и умеренности ... выражали словом «целомудрие»', 2, '["imported","akhlaq","test-1","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"целомудрие","answers":["целомудрие","целомудрием","нравственная чистота"],"required":["целомудр"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"положение же прямоты и умеренности ... выражали словом «целомудрие»","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q17', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: Ислам повелевает держаться вдали от крайностей и во всём соблюдать ________.', 'Начало первой главы задаёт общий принцип нравственного пути: избегать крайностей и держаться меры.\n\nSource: во всём соблюдать умеренность и меру', 1, '["imported","akhlaq","test-1","fill_blank"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"умеренность и меру","answers":["умеренность и меру","умеренность","меру","равновесие"],"required":["умерен"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"во всём соблюдать умеренность и меру","sourceQuestionType":"fill_blank","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q18', 'Akhlaq', 'SHORT_TEXT', 'Что, согласно первой главе, нужно прежде всего сделать тому, кто хочет достичь желаемого нравственного состояния?', 'Автор говорит, что украшение прекрасными свойствами начинается с оставления дурных качеств.\n\nSource: прежде всего необходимо оставить дурные качества', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"оставить дурные качества","answers":["оставить дурные качества","избавиться от дурных качеств","оставить дурные привычки","очиститься от дурного"],"required":["дурн","качеств"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"прежде всего необходимо оставить дурные качества","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q19', 'Akhlaq', 'TRUE_FALSE', 'Верно или неверно: пока человек не знает собственных изъянов, у него нет возможности избавиться от них.', 'Текст подчёркивает, что осознание собственных недостатков является необходимым условием их исправления.\n\nSource: пока мы не знаем собственных изъянов, у нас нет возможности избавиться от них', 1, '["imported","akhlaq","test-1","true_false"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"верно","answers":["верно","да","правда","истинно"],"required":["верн"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"пока мы не знаем собственных изъянов, у нас нет возможности избавиться от них","sourceQuestionType":"true_false","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q20', 'Akhlaq', 'SHORT_TEXT', 'Что названо первой ступенью устранения недостатков?', 'Автор подчёркивает, что человек должен сначала ощутить свои изъяны и упущения.\n\nSource: Ощущение — первая ступень устранения недостатков', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"ощущение","answers":["ощущение","осознание","ощущение недостатков","осознание недостатков"],"required":["ощущ"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Ощущение — первая ступень устранения недостатков","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q21', 'Akhlaq', 'SHORT_TEXT', 'К каким основным источникам должен обращаться человек, чтобы узнать ясно запрещённые поступки?', 'В разделе о самоотчёте говорится, что границы грехов обозначены Кораном и Сунной.\n\nSource: ясно и отчётливо изложена посредством ... Благородным Кораном и достоверной Сунной', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"к Корану и достоверной Сунне","answers":["к Корану и Сунне","к Корану и достоверной Сунне","к основным источникам","к Божественному откровению"],"required":["коран","сунн"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"ясно и отчётливо изложена посредством ... Благородным Кораном и достоверной Сунной","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q22', 'Akhlaq', 'SHORT_TEXT', 'Что, по тексту, помогает человеку не оставаться один на один с духовной сжатостью?', 'В первой главе фактор окружения показан как поддержка, ведущая человека к добру.\n\nSource: Доброе окружение, хорошие друзья ведут человека к добру', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"доброе окружение и хорошие друзья","answers":["доброе окружение","хорошие друзья","доброе окружение и хорошие друзья","хороший друг"],"required":["друз"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Доброе окружение, хорошие друзья ведут человека к добру","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q23', 'Akhlaq', 'SHORT_TEXT', 'Что означает термин «садд аз-зараи» в словарном смысле?', 'В разделе о защите от дурных нравов этот принцип объясняется как удаление средств и путей, которые могут привести к запретному.\n\nSource: садд аз-зараи означает «устранение средств, ведущих к чему-либо»', 2, '["imported","akhlaq","test-1","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"устранение средств, ведущих к чему-либо","answers":["устранение средств, ведущих к чему-либо","устранение средств, ведущих к запретному","устранение средств","пресечение путей к запретному"],"required":["устран"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"садд аз-зараи означает «устранение средств, ведущих к чему-либо»","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q24', 'Akhlaq', 'SHORT_TEXT', 'Что названо первым шагом к вознесению человека к малакуту?', 'Открытие миру малакута начинается с выхода человека из плена низшего «я» и телесных желаний.\n\nSource: первым шагом ... является преодоление желаний и требований нафса', 2, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"преодоление желаний и требований нафса","answers":["преодоление желаний нафса","преодоление требований нафса","преодоление нафса","преодоление желаний и требований нафса"],"required":["преодол","нафс"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"первым шагом ... является преодоление желаний и требований нафса","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_01_q25', 'Akhlaq', 'SHORT_TEXT', 'Согласно приведённому хадису, какой сосуд сын Адама не наполнял хуже всего?', 'В конце первой тестовой части автор использует этот хадис, чтобы подчеркнуть важность меры в еде и питье.\n\nSource: Сын Адама не наполнял сосуда хуже своего желудка', 1, '["imported","akhlaq","test-1","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"свой желудок","answers":["желудок","свой желудок","желудка"],"required":["желуд"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Сын Адама не наполнял сосуда хуже своего желудка","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q01', 'Akhlaq', 'SHORT_TEXT', 'Что Фатима принесла Пророку, после чего он сказал, что это первая пища за три дня?', 'Этот эпизод показывает меру воздержания в жизни Пророка.\n\nSource: досточтимая Фатима вошла с куском сухого хлеба', 1, '["imported","akhlaq","test-2","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"кусок сухого хлеба","answers":["кусок сухого хлеба","сухой хлеб","хлеб"],"required":["хлеб"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"досточтимая Фатима вошла с куском сухого хлеба","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q02', 'Akhlaq', 'TRUE_FALSE', 'Верно или неверно: семья Пророка в Медине ни разу не насыщалась пшеничным хлебом три дня подряд.', 'В тексте это приведено как пример пророческой простоты и воздержания.\n\nSource: его семья ни разу не насыщалась пшеничным хлебом три дня подряд', 1, '["imported","akhlaq","test-2","true_false"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"верно","answers":["верно","да","правда","истинно"],"required":["верн"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"его семья ни разу не насыщалась пшеничным хлебом три дня подряд","sourceQuestionType":"true_false","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q03', 'Akhlaq', 'SHORT_TEXT', 'К чему, по тексту, приводит множество разнообразных блюд?', 'Автор связывает разнообразие пищи с искусственным аппетитом, перееданием, расточительством и беспечностью.\n\nSource: вызывает в человеке искусственный аппетит ... становится расточительством', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"к искусственному аппетиту и расточительству","answers":["к искусственному аппетиту","к чрезмерной пище","к расточительству","к аппетиту и расточительству"],"required":["аппетит","расточ"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"вызывает в человеке искусственный аппетит ... становится расточительством","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q04', 'Akhlaq', 'SHORT_TEXT', 'Как Бедиуззаман определяет волю в этом разделе?', 'Воля описана как малое, но серьёзное основание ответственности человека.\n\nSource: Воля ... есть «склонность или распоряжение склонностью»', 2, '["imported","akhlaq","test-2","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"склонность или распоряжение склонностью","answers":["склонность или распоряжение склонностью","склонность","распоряжение склонностью"],"required":["склон"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Воля ... есть «склонность или распоряжение склонностью»","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q05', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: Коран напоминает об истине зикра аятом: «Совершай ________, чтобы помнить Меня».', 'Раздел об авраде и азкаре связывает молитву с поминанием Аллаха.\n\nSource: Совершай намаз, чтобы помнить Меня', 1, '["imported","akhlaq","test-2","fill_blank"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"намаз","answers":["намаз","молитву","ритуальную молитву"],"required":["намаз"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Совершай намаз, чтобы помнить Меня","sourceQuestionType":"fill_blank","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q06', 'Akhlaq', 'SHORT_TEXT', 'На что прежде всего опирается метод созерцательного размышления?', 'Автор отличает настоящее размышление от сухих фантазий и требует знания предмета.\n\nSource: Созерцательное размышление прежде всего опирается на первоначальное и предварительное знание', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"на первоначальное и предварительное знание","answers":["на первоначальное знание","на предварительное знание","на знания","на сведения о предмете"],"required":["знан"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Созерцательное размышление прежде всего опирается на первоначальное и предварительное знание","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q07', 'Akhlaq', 'SHORT_TEXT', 'Что означает «ихлас» в начале второй главы?', 'Ихлас описан как чистота сердца, удалённость от показного благочестия и служение ради Аллаха.\n\nSource: Ихлас означает правдивость, сердечную чистоту, незамутнённость и цельность', 1, '["imported","akhlaq","test-2","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"искренность перед Аллахом","answers":["искренность","искренность перед Аллахом","сердечная чистота","чистота намерения"],"required":["искрен"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Ихлас означает правдивость, сердечную чистоту, незамутнённость и цельность","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q08', 'Akhlaq', 'SHORT_TEXT', 'От чего, согласно тексту, целиком зависит принятие деяний у Аллаха?', 'Автор подчёркивает, что даже внешне большие дела без ихласа остаются безжизненными.\n\nSource: принятие деяний у Аллаха целиком зависит от ихласа', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"от ихласа","answers":["от ихласа","от искренности","от чистоты намерения"],"required":["ихлас"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"принятие деяний у Аллаха целиком зависит от ихласа","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q09', 'Akhlaq', 'SHORT_TEXT', 'Какое первое правило для обретения ихласа указывает Пир?', 'В делах не должно быть земных ожиданий; единственной целью должно быть довольство Аллаха.\n\nSource: Первое правило ... соблюдение Божьего довольства в совершаемых деяниях', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"соблюдение Божьего довольства","answers":["соблюдение Божьего довольства","довольство Аллаха","искать довольство Аллаха","цель — довольство Аллаха"],"required":["довольств"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Первое правило ... соблюдение Божьего довольства в совершаемых деяниях","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q10', 'Akhlaq', 'SHORT_TEXT', 'Что, помимо правдивой речи, включает в себя сыдк?', 'Сыдк в тексте раскрывается как широкое понятие: правдивость речи, поведения, внутреннего и внешнего состояния.\n\nSource: наряду с правдивой речью включает в себя и правильное поведение', 2, '["imported","akhlaq","test-2","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"правильное поведение","answers":["правильное поведение","правдивое поведение","правдивость в поступках","верное поведение"],"required":["поведен"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"наряду с правдивой речью включает в себя и правильное поведение","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q11', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: правдивость ведёт человека к добру, а добро ведёт его в ________.', 'Хадис в разделе о сыдке показывает духовное последствие правдивости.\n\nSource: Правдивость ведёт человека к добру, а добро ведёт его в Рай', 1, '["imported","akhlaq","test-2","fill_blank"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"Рай","answers":["Рай","рай","в Рай"],"required":["рай"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Правдивость ведёт человека к добру, а добро ведёт его в Рай","sourceQuestionType":"fill_blank","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q12', 'Akhlaq', 'SHORT_TEXT', 'Что означает «аманат» в разделе о надёжности?', 'Аманат связан с доверием, хранением порученного и отсутствием предательства.\n\nSource: Аманат означает быть достойным доверия', 1, '["imported","akhlaq","test-2","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"быть достойным доверия","answers":["быть достойным доверия","доверие","надёжность","хранить вверенное"],"required":["довер"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Аманат означает быть достойным доверия","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q13', 'Akhlaq', 'SHORT_TEXT', 'Когда, согласно хадису, аманат будет утрачен?', 'Поручение дела неподходящему человеку показано как утрата аманата и нарушение порядка.\n\nSource: Когда дело будет поручено тому, кто его недостоин', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"когда дело поручат недостойному","answers":["когда дело поручено недостойному","когда дело поручат тому, кто недостоин","когда дело поручено тому, кто его недостоин"],"required":["дел","недосто"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Когда дело будет поручено тому, кто его недостоин","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q14', 'Akhlaq', 'SHORT_TEXT', 'Какой путь назван самым коротким и надёжным способом победить противника?', 'Раздел о прощении подчёркивает, что доброе обращение разрушает вражду лучше ответного зла.\n\nSource: самый короткий и надёжный путь победить противника — ответить добром на его зло', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"ответить добром на зло","answers":["ответить добром на зло","отвечать добром на зло","добром на зло","отвести зло добром"],"required":["добром","зло"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"самый короткий и надёжный путь победить противника — ответить добром на его зло","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q15', 'Akhlaq', 'TRUE_FALSE', 'Верно или неверно: сердца, исполненные сострадания, не ждут ответной благодарности.', 'Сострадание в тексте описано как чистое, бескорыстное и свободное от расчёта.\n\nSource: Сердца, исполненные сострадания, чисты; они не ждут ответной благодарности', 1, '["imported","akhlaq","test-2","true_false"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"верно","answers":["верно","да","правда","истинно"],"required":["верн"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Сердца, исполненные сострадания, чисты; они не ждут ответной благодарности","sourceQuestionType":"true_false","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q16', 'Akhlaq', 'SHORT_TEXT', 'Сострадание в служении вере — это не стремление спастись самому, а что?', 'Автор поднимает сострадание до уровня самоотверженного стремления оживлять и спасать других.\n\nSource: это не стремление спастись, а усилие и усердие ради спасения других', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"усилие ради спасения других","answers":["усилие ради спасения других","спасение других","старание спасать других","даровать жизнь другим"],"required":["спас","друг"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"это не стремление спастись, а усилие и усердие ради спасения других","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q17', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: Аллах возносит того, кто проявляет ________.', 'В разделе о смирении противопоставлены возвышение смиренного и низвержение высокомерного.\n\nSource: Аллах всё выше и выше возносит того, кто проявляет смирение', 1, '["imported","akhlaq","test-2","fill_blank"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"смирение","answers":["смирение","скромность","смиренность"],"required":["смир"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Аллах всё выше и выше возносит того, кто проявляет смирение","sourceQuestionType":"fill_blank","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q18', 'Akhlaq', 'SHORT_TEXT', 'На чём, согласно образу из текста, растёт роза?', 'Образ розы, растущей в земле, используется для объяснения скромности и самоуничижения.\n\nSource: Роза растёт в земле', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"на земле","answers":["на земле","в земле","земля"],"required":["земл"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Роза растёт в земле","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q19', 'Akhlaq', 'SHORT_TEXT', 'Что означает целомудрие в общем смысле?', 'Целомудрие раскрывается как удержание желаний в дозволенных пределах и закрытость для запретного.\n\nSource: взять под контроль телесные и животные желания', 2, '["imported","akhlaq","test-2","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"контроль телесных и животных желаний","answers":["контроль телесных желаний","держать желания под контролем","контролировать телесные и животные желания","сторониться разврата"],"required":["контрол","желан"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"взять под контроль телесные и животные желания","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q20', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: по словам Бедиуззамана, круг дозволенного широк и достаточен для ________.', 'Эта мысль поддерживает идею жить в пределах дозволенного и не входить в запретное.\n\nSource: Круг дозволенного широк и достаточен для радости', 1, '["imported","akhlaq","test-2","fill_blank"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"радости","answers":["радости","счастья","наслаждения"],"required":["радост"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Круг дозволенного широк и достаточен для радости","sourceQuestionType":"fill_blank","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q21', 'Akhlaq', 'SHORT_TEXT', 'С каким именем Аллаха текст связывает щедрость?', 'Щедрость описана как нравственное созвучие с именем Аллаха Джавад.\n\nSource: Щедрость — это вхождение в созвучие с именем Аллаха Джавад', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"Джавад","answers":["Джавад","аль-Джавад","имя Джавад","Щедрый"],"required":["джавад"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Щедрость — это вхождение в созвучие с именем Аллаха Джавад","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q22', 'Akhlaq', 'SHORT_TEXT', 'Как называется качество, при котором человек, сам нуждаясь, предпочитает других себе?', 'Исар является высшей степенью щедрости и самоотверженности.\n\nSource: сам будучи нуждающимся, предпочитает других своему нафсу ... называется исар', 2, '["imported","akhlaq","test-2","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"исар","answers":["исар","предпочтение других себе","самоотверженное предпочтение"],"required":["исар"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"сам будучи нуждающимся, предпочитает других своему нафсу ... называется исар","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q23', 'Akhlaq', 'SHORT_TEXT', 'Что, согласно хадису, не испытывает тот, кто соблюдает бережливость?', 'Бережливость представлена как путь сохранения достоинства и жизни в пределах дозволенного.\n\nSource: Кто соблюдает бережливость, тот не испытывает ни бедности, ни стеснённости', 1, '["imported","akhlaq","test-2","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"бедности и стеснённости","answers":["бедности","стеснённости","бедности и стеснённости","нужды"],"required":["бедн"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Кто соблюдает бережливость, тот не испытывает ни бедности, ни стеснённости","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q24', 'Akhlaq', 'SHORT_TEXT', 'К каким трём категориям праведные предшественники сводили основные виды терпения?', 'Три вида терпения охватывают защиту от греха, перенос испытаний и постоянство в послушании.\n\nSource: держаться вдали от греха, выносить бедствия и быть постоянным в поклонении', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"держаться вдали от греха, выносить бедствия, быть постоянным в поклонении","answers":["держаться вдали от греха, выносить бедствия, быть постоянным в поклонении","терпение перед грехом, бедствиями и поклонением","избегать греха, переносить беды, постоянство в поклонении"],"required":["грех","бед","поклон"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"держаться вдали от греха, выносить бедствия и быть постоянным в поклонении","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_02_q25', 'Akhlaq', 'SHORT_TEXT', 'Назовите один из критериев верности, перечисленных в конце тестового блока.', 'Верность раскрывается через отношение к Аллаху, людям, дружбе и всему добру, полученному человеком.\n\nSource: Верность — это стойкость в слове, данном Аллаху, соблюдение обета, данного людям', 2, '["imported","akhlaq","test-2","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"стойкость в слове, данном Аллаху","answers":["стойкость в слове, данном Аллаху","соблюдение обета людям","исполнение права дружбы","искренность и преданность"],"required":["стойк","обет","дружб","предан"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Верность — это стойкость в слове, данном Аллаху, соблюдение обета, данного людям","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q01', 'Akhlaq', 'SHORT_TEXT', 'Как в тексте называется благожелательное, положительное мнение о других?', 'Хуснузан в этом разделе определяется как доброжелательность, положительное мышление и благой взгляд на людей и события.\n\nSource: Состояние человека... называется хуснузан.', 1, '["imported","akhlaq","test-3","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"хуснузан","answers":["хуснузан","благое мнение","доброжелательность","положительное мнение"],"required":["хуснузан"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Состояние человека... называется хуснузан.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q02', 'Akhlaq', 'SHORT_TEXT', 'Как в тексте называется дурное подозрение или предвзятое мнение о человеке?', 'Автор противопоставляет хуснузану суизан: дурное подозрение, построенное на догадках и предвзятости.\n\nSource: Дурное же мнение о ком-либо называется суизан.', 1, '["imported","akhlaq","test-3","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"суизан","answers":["суизан","дурное подозрение","предвзятое мнение","дурное мнение"],"required":["суизан"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Дурное же мнение о ком-либо называется суизан.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q03', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: в спорных случаях, по мысли автора, лучше ошибиться в ________, чем оказаться правым в суизане.', 'Текст учит предпочитать доброе толкование поступков людей, даже если такое мнение окажется ошибочным.\n\nSource: лучше ошибиться в хуснузане, чем оказаться правым в суизане.', 2, '["imported","akhlaq","test-3","fill_blank"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"хуснузане","answers":["хуснузане","хуснузан","благом мнении","добром мнении"],"required":["хуснузан"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"лучше ошибиться в хуснузане, чем оказаться правым в суизане.","sourceQuestionType":"fill_blank","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q04', 'Akhlaq', 'SHORT_TEXT', 'Какой принцип сочетает благое мнение с осторожностью в поручении ответственных дел?', 'Автор допускает внимательность к признакам нифака в общественных делах, но не превращает её в осуждение человека.\n\nSource: хуснузан, но адем-и итимад [осторожное недоверие]', 2, '["imported","akhlaq","test-3","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"хуснузан, но адем-и итимад","answers":["хуснузан, но адем-и итимад","хуснузан и осторожное недоверие","благое мнение и осторожное недоверие","хуснузан с осторожностью"],"required":["хуснузан","осторож"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"хуснузан, но адем-и итимад [осторожное недоверие]","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q05', 'Akhlaq', 'TRUE_FALSE', 'Верно ли: автор советует избегать мест и поступков, которые могут вызвать подозрение у других?', 'В разделе о благомыслии отдельно подчёркивается необходимость не давать повода для дурных подозрений.\n\nSource: Держитесь подальше от мест, где вас могут заподозрить.', 1, '["imported","akhlaq","test-3","true_false"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"Верно","answers":["верно","да","истина","правильно"],"required":["верн"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Держитесь подальше от мест, где вас могут заподозрить.","sourceQuestionType":"true_false","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q06', 'Akhlaq', 'SHORT_TEXT', 'Какое качество определяется как состояние степенности, спокойствия, осмотрительности и усердия?', 'В тексте серьезность связана с ответственным отношением к делу, спокойствием и отсутствием легкомыслия.\n\nSource: Серьезность — это состояние степенности, спокойствия, осмотрительности и усердия.', 1, '["imported","akhlaq","test-3","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"серьезность","answers":["серьезность","серьёзность"],"required":["серьез","серьёз"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Серьезность — это состояние степенности, спокойствия, осмотрительности и усердия.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q07', 'Akhlaq', 'SHORT_TEXT', 'Каким словом в тексте обозначен мягкий стиль обращения, которым даже фараону следовало разъяснять истину?', 'Раздел о сладкой речи показывает, что истина должна разъясняться мягко даже самому жёсткому собеседнику.\n\nSource: истину и правду всё равно следует разъяснять кавл-и леййин.', 2, '["imported","akhlaq","test-3","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"кавл-и леййин","answers":["кавл-и леййин","мягкое слово","мягкая речь","мягкий стиль"],"required":["мягк"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"истину и правду всё равно следует разъяснять кавл-и леййин.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q08', 'Akhlaq', 'TRUE_FALSE', 'Верно ли: по тексту грубые манеры и суровое поведение помогают удержать людей рядом с проповедником?', 'Текст говорит обратное: грубость отталкивает людей, а мягкость становится центром притяжения.\n\nSource: грубые манеры и суровое поведение заставят людей разбежаться от нас.', 2, '["imported","akhlaq","test-3","true_false"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"Неверно","answers":["неверно","нет","ложь","неправильно"],"required":["невер","нет"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"грубые манеры и суровое поведение заставят людей разбежаться от нас.","sourceQuestionType":"true_false","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q09', 'Akhlaq', 'SHORT_TEXT', 'Как называется высота духа, при которой сердце стремится охватить всё человечество и желать наставления каждому?', 'Широта совести описывается как раскрытость сердца ко всем людям, прощение и желание вечного счастья каждому.\n\nSource: Широта совести — это высота духа.', 2, '["imported","akhlaq","test-3","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"широта совести","answers":["широта совести","раскрытие совести","широкая совесть"],"required":["совест"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Широта совести — это высота духа.","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q10', 'Akhlaq', 'SHORT_TEXT', 'Какое качество в разделе о мужестве автор связывает с бесстрашием перед трудностями и с терпением?', 'В этом блоке мужество понимается как духовная стойкость и готовность идти правильным путём несмотря на препятствия.\n\nSource: 18. Мужество', 1, '["imported","akhlaq","test-3","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"мужество","answers":["мужество","смелость","храбрость","шаджаат"],"required":["мужеств"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"18. Мужество","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q11', 'Akhlaq', 'SHORT_TEXT', 'Какое качество означает совершать добро и служение без ожидания личной выгоды?', 'Раздел о бескорыстии раскрывает нравственную ценность служения, не связанного с личным расчётом.\n\nSource: 19. Бескорыстие', 2, '["imported","akhlaq","test-3","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"бескорыстие","answers":["бескорыстие","безвозмездность","служение без выгоды","отсутствие личной выгоды"],"required":["бескорыст"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"19. Бескорыстие","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q12', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: в прежних обителях у входа писали: «________, о человек!»', 'В разделе об адабе автор подчёркивает, что благовоспитанность должна встречать человека уже у входа и стать частью его природы.\n\nSource: на дверях текке и медресе было написано: «Адаб, о человек!»', 1, '["imported","akhlaq","test-3","fill_blank"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"Адаб","answers":["адаб","Адаб"],"required":["адаб"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"на дверях текке и медресе было написано: «Адаб, о человек!»","sourceQuestionType":"fill_blank","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q13', 'Akhlaq', 'SHORT_TEXT', 'Что, по тексту, воздействует на людей сильнее, чем украшенные слова?', 'Автор утверждает, что подлинное влияние исходит от состояния, поведения и адаба, а не от красивой речи самой по себе.\n\nSource: На людей воздействуют не пустые, пусть и украшенные слова, а человеческие поступки и манеры.', 2, '["imported","akhlaq","test-3","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"поступки и манеры","answers":["поступки и манеры","состояние, манеры и поведение","человеческие поступки","поведение и адаб"],"required":["поступ","манер"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"На людей воздействуют не пустые, пусть и украшенные слова, а человеческие поступки и манеры.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q14', 'Akhlaq', 'SHORT_TEXT', 'Как называется качество принимать право и истину, кем бы они ни были высказаны?', 'Инсаф в тексте связан с признанием истины, уважением прав других и справедливостью вопреки нафсу.\n\nSource: Инсаф — это принимать и признавать право и истину.', 2, '["imported","akhlaq","test-3","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"инсаф","answers":["инсаф","совестливая справедливость","справедливость","признание истины"],"required":["инсаф"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Инсаф — это принимать и признавать право и истину.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q15', 'Akhlaq', 'SHORT_TEXT', 'Какую цель должна иметь справедливая критика согласно разделу об инсафе?', 'Критика ценна не как победа в споре, а как средство приблизиться к истине и правде.\n\nSource: справедливый критик должен ставить себе целью лишь выявление истины и правды.', 3, '["imported","akhlaq","test-3","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"выявление истины","answers":["выявление истины","проявление истины","обрести правду","найти истину","выявление истины и правды"],"required":["истин"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"справедливый критик должен ставить себе целью лишь выявление истины и правды.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q16', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: в справедливом диспуте важно не оказаться правым, а чтобы проявилась ________.', 'Автор критикует радость от собственной правоты: цель обсуждения — не самолюбие, а явление истины.\n\nSource: важно не оказаться правым, а чтобы проявилась истина.', 2, '["imported","akhlaq","test-3","fill_blank"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"истина","answers":["истина","правда","истина и правда"],"required":["истин"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"важно не оказаться правым, а чтобы проявилась истина.","sourceQuestionType":"fill_blank","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q17', 'Akhlaq', 'SHORT_TEXT', 'Какое средство выражения автор называет великим божественным даром человеку?', 'В начале третьей главы язык представлен как дар, который может вести человека как к возвышению, так и к падению.\n\nSource: Всевышний Творец даровал человеку язык — великий божественный дар.', 1, '["imported","akhlaq","test-3","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"язык","answers":["язык","речь","способность к речи","способность к ясному изъяснению"],"required":["язык"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Всевышний Творец даровал человеку язык — великий божественный дар.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q18', 'Akhlaq', 'SHORT_TEXT', 'Что, согласно хадису в тексте, должен делать верующий в Аллаха и Последний день: говорить благое или что?', 'Этот хадис задаёт главный критерий речи: говорить только благое, иначе удерживать язык.\n\nSource: пусть говорит благое или молчит.', 1, '["imported","akhlaq","test-3","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"молчать","answers":["молчать","хранить молчание","молчание"],"required":["молч"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"пусть говорит благое или молчит.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q19', 'Akhlaq', 'SHORT_TEXT', 'Как называется произнесение за спиной человека слов, которые огорчили бы его в лицо?', 'Так в тексте определяется гыйбат: неприятное для человека упоминание в его отсутствие.\n\nSource: Гыйбат — это произнесение за спиной человека слов, которые огорчили бы его.', 1, '["imported","akhlaq","test-3","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"гыйбат","answers":["гыйбат","злословие","злословие за спиной","поношение за спиной"],"required":["гыйбат","злослов"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Гыйбат — это произнесение за спиной человека слов, которые огорчили бы его.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q20', 'Akhlaq', 'SHORT_TEXT', 'Если сказанное о человеке за его спиной не соответствует действительности, как это называется в объяснении хадиса?', 'Хадис различает злословие о реальном недостатке и клевету, если сказанного в человеке нет.\n\nSource: А если этого в нём нет, то это клевета.', 2, '["imported","akhlaq","test-3","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"клевета","answers":["клевета","навет","ложное обвинение"],"required":["клевет"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"А если этого в нём нет, то это клевета.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q21', 'Akhlaq', 'SHORT_TEXT', 'Назовите один из трёх признаков лицемера, перечисленных в хадисе о лжи.', 'Текст приводит три признака: ложь в речи, нарушение обещания и предательство доверенного.\n\nSource: когда говорит — лжёт, когда обещает — не исполняет.', 1, '["imported","akhlaq","test-3","short_answer"]', NULL, 'REGEX', '{"caseSensitive":false,"answer":"когда говорит — лжёт","answers":["когда говорит — лжёт","говорит и лжет","когда обещает — не исполняет","не исполняет обещание","когда доверяют — предает","предает доверенное"],"required":[],"forbidden":[],"pattern":"(лж|обещ|довер|преда)","flags":"iu","sourceQuote":"когда говорит — лжёт, когда обещает — не исполняет.","sourceQuestionType":"short_answer","sourceGradingMode":"regex"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q22', 'Akhlaq', 'SHORT_TEXT', 'Как называется полемический спор, где словесными играми пытаются представить ложное истинным?', 'Автор отличает джадаль от полезного обсуждения: джадаль стремится не к истине, а к победе словесной ловкостью.\n\nSource: стремление посредством словесных игр... представить ложное истинным.', 2, '["imported","akhlaq","test-3","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"джадаль","answers":["джадаль","диалектика","полемический спор"],"required":["джадал","диалект"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"стремление посредством словесных игр... представить ложное истинным.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q23', 'Akhlaq', 'SHORT_TEXT', 'Как называется злонамеренная передача слов от одного человека другому, ведущая к обиде и разладу?', 'Намима разрушает братские связи, потому что разносит слова так, что они становятся причиной раздора.\n\nSource: Перенос слов, называемый также намима... означает передачу от одного человека другому слов.', 2, '["imported","akhlaq","test-3","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"намима","answers":["намима","сплетничество","перенос слов","злонамеренное перенесение слов"],"required":["намим","сплет"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Перенос слов, называемый также намима... означает передачу от одного человека другому слов.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q24', 'Akhlaq', 'SHORT_TEXT', 'Какое чувство в разделе о страсти названо опаснейшим оружием, ослабляющим волю?', 'Автор описывает страсть как средство, через которое шайтан может ослабить волю и подчинить человека.\n\nSource: страсть — опаснейшее оружие, ослабляющее волю.', 2, '["imported","akhlaq","test-3","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"страсть","answers":["страсть","страсть вожделения","вожделение","шахват"],"required":["страст","вождел"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"страсть — опаснейшее оружие, ослабляющее волю.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_03_q25', 'Akhlaq', 'SHORT_TEXT', 'Какое установление названо системой, позволяющей использовать чувство страсти в правильных границах?', 'В тексте брак представлен как защищённая среда и правильное направление для чувства страсти.\n\nSource: Система, установленная Всевышним Аллахом... — это брак.', 2, '["imported","akhlaq","test-3","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"брак","answers":["брак","супружество","женитьба","семейная жизнь"],"required":["брак","супруж"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Система, установленная Всевышним Аллахом... — это брак.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q01', 'Akhlaq', 'SHORT_TEXT', 'Какой термин в тексте обозначает вспышку ярости, негодования и желание отомстить?', 'Раздел начинается с определения газаба как гнева, вспышки и состояния агрессивного возбуждения.\n\nSource: газаб — гнев — означает поддаться вспышке, ярость, негодование.', 1, '["imported","akhlaq","test-4","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"газаб","answers":["газаб","гнев","ярость","гнев-ярость"],"required":["гнев","газаб"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"газаб — гнев — означает поддаться вспышке, ярость, негодование.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q02', 'Akhlaq', 'SHORT_TEXT', 'Как называется противоположность гневу в этом разделе?', 'Хильм описан как степенность, достоинство и умение не принимать поспешных решений под влиянием гнева.\n\nSource: Противоположностью гневу является хильм.', 1, '["imported","akhlaq","test-4","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"хильм","answers":["хильм","кроткая выдержанность","выдержанность","кротость"],"required":["хильм"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Противоположностью гневу является хильм.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q03', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: Пророк несколько раз повторил просившему наставления человеку: «Владей своим ________!»', 'Повторение этого наставления подчёркивает важность контроля над одной из самых уязвимых сторон человека.\n\nSource: каждый раз повторял ему: «Владей своим гневом!»', 1, '["imported","akhlaq","test-4","fill_blank"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"гневом","answers":["гневом","гнев","яростью"],"required":["гнев"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"каждый раз повторял ему: «Владей своим гневом!»","sourceQuestionType":"fill_blank","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q04', 'Akhlaq', 'SHORT_TEXT', 'Кого хадис называет по-настоящему сильным человеком?', 'Сила в тексте измеряется не физической победой, а властью над собой в час ярости.\n\nSource: по-настоящему силен тот, кто побеждает свой нафс, когда гневается.', 2, '["imported","akhlaq","test-4","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"того, кто владеет собой в гневе","answers":["кто владеет собой в гневе","кто побеждает свой нафс в гневе","кто сдерживает себя в ярости","кто контролирует гнев"],"required":["гнев","влад"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"по-настоящему силен тот, кто побеждает свой нафс, когда гневается.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q05', 'Akhlaq', 'SHORT_TEXT', 'На что искренний верующий должен направлять свой гнев, если он хочет сохранить правильную меру?', 'Гнев не должен служить эгоизму; его нужно подчинять правде, воспитанию нафса и защите угнетённых.\n\nSource: должен направлять свой гнев на то, чем недоволен Аллах.', 2, '["imported","akhlaq","test-4","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"на то, чем недоволен Аллах","answers":["на то, чем недоволен Аллах","на дела, которыми недоволен Аллах","на мятежи своего нафса","против притеснения людей"],"required":["Аллах","недовол"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"должен направлять свой гнев на то, чем недоволен Аллах.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q06', 'Akhlaq', 'SHORT_TEXT', 'Какой термин означает желание, чтобы блага другого были отняты у него и достались завистнику?', 'Хасад описан как неспособность вынести чужие достоинства и желание лишить другого его благ.\n\nSource: Хасад означает, что человек не может вынести благ и достоинств, дарованных другим.', 1, '["imported","akhlaq","test-4","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"хасад","answers":["хасад","зависть","ревность и зависть"],"required":["хасад","завист"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Хасад означает, что человек не может вынести благ и достоинств, дарованных другим.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q07', 'Akhlaq', 'TRUE_FALSE', 'Верно ли: в тексте сказано, что зависть пожирает добрые дела так же, как огонь пожирает дрова?', 'Хадис в этом разделе подчёркивает разрушительное действие зависти на добрые деяния.\n\nSource: Как огонь пожирает дрова, так зависть пожирает добрые дела.', 1, '["imported","akhlaq","test-4","true_false"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"Верно","answers":["верно","да","истина","правильно"],"required":["верн"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Как огонь пожирает дрова, так зависть пожирает добрые дела.","sourceQuestionType":"true_false","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q08', 'Akhlaq', 'SHORT_TEXT', 'Как называется благое восхищение, когда человек хочет похожего блага себе, но не желает исчезновения блага у другого?', 'Гыбта отличается от зависти отсутствием желания лишить другого его дара.\n\nSource: Гыбта... не желая исчезновения благ... хочет, чтобы такие же блага были и у него.', 2, '["imported","akhlaq","test-4","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"гыбта","answers":["гыбта","благая зависть","доброе восхищение","восхищённое стремление"],"required":["гыбт"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Гыбта... не желая исчезновения благ... хочет, чтобы такие же блага были и у него.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q09', 'Akhlaq', 'SHORT_TEXT', 'Какое качество определяется как состояние, когда человек считает себя великим, а других презирает и унижает?', 'Высокомерие в тексте связано с ложным возвышением себя и унижением рабов Аллаха.\n\nSource: Высокомерие — это когда человек считает себя великим, а других рабов Аллаха презирает.', 1, '["imported","akhlaq","test-4","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"высокомерие","answers":["высокомерие","гордыня","кичливость","надменность"],"required":["высокомер","гордын"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Высокомерие — это когда человек считает себя великим, а других рабов Аллаха презирает.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q10', 'Akhlaq', 'SHORT_TEXT', 'Какое качество названо противоположностью и лекарством от высокомерия?', 'Лекарство от гордыни — видеть своё место перед Истиной и относить блага к Аллаху, а не к себе.\n\nSource: Противоположность высокомерию и одновременно лекарство от него — смирение.', 2, '["imported","akhlaq","test-4","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"смирение","answers":["смирение","скромность","самоуничижение","кротость"],"required":["смир","скром"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Противоположность высокомерию и одновременно лекарство от него — смирение.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q11', 'Akhlaq', 'SHORT_TEXT', 'Что, согласно хадису, грозит тому, кто порицает брата-мусульманина за ошибку или недостаток?', 'Текст предостерегает от порицания людей: осуждающий может сам быть испытан тем же недостатком.\n\nSource: он сам не умрет, пока не совершит того же.', 2, '["imported","akhlaq","test-4","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"сам совершит то же","answers":["сам совершит то же","не умрет, пока не совершит того же","испытает тот же проступок","совершит такую же ошибку"],"required":["соверш","то же"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"он сам не умрет, пока не совершит того же.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q12', 'Akhlaq', 'SHORT_TEXT', 'Какое качество подразумевает само слово «му’мин» в объяснении автора?', 'Истинный верующий должен быть человеком, рядом с которым другие чувствуют безопасность.\n\nSource: само слово «му’мин»... указывает на человека надёжного.', 1, '["imported","akhlaq","test-4","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"надёжность","answers":["надёжность","надежность","безопасность","тот, кому доверяют","доверие"],"required":["надеж","надёж","довер"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"само слово «му’мин»... указывает на человека надёжного.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q13', 'Akhlaq', 'TRUE_FALSE', 'Верно ли: текст разрешает насмешки над людьми, если они оформлены как шутки?', 'Текст прямо запрещает шутки и действия, цель которых — унизить другого человека.\n\nSource: так же запретил насмехаться над людьми.', 1, '["imported","akhlaq","test-4","true_false"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"Неверно","answers":["неверно","нет","ложь","неправильно"],"required":["невер","нет"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"так же запретил насмехаться над людьми.","sourceQuestionType":"true_false","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q14', 'Akhlaq', 'SHORT_TEXT', 'Как называется преступление предела и посягательство на право другого?', 'Зульм включает посягательство на права Аллаха или права Его рабов и имеет разные степени тяжести.\n\nSource: Зульм означает преступление предела и посягательство на право другого.', 1, '["imported","akhlaq","test-4","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"зульм","answers":["зульм","несправедливость","притеснение","угнетение"],"required":["зульм","несправ"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Зульм означает преступление предела и посягательство на право другого.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q15', 'Akhlaq', 'SHORT_TEXT', 'К кому, согласно приведённому аяту, мусульманам не следует склоняться даже в малой степени?', 'Текст подчёркивает, что даже сочувственное склонение к зульму постепенно втягивает человека в эту нечистоту.\n\nSource: Ни в коем случае не склоняйтесь к тем, кто поступает несправедливо.', 2, '["imported","akhlaq","test-4","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"к притеснителям","answers":["к притеснителям","к тем, кто поступает несправедливо","к угнетателям","к совершающим зульм"],"required":["притесн","несправ"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Ни в коем случае не склоняйтесь к тем, кто поступает несправедливо.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q16', 'Akhlaq', 'SHORT_TEXT', 'Где, согласно наставлению Пророка человеку, желавшему джихада, находится его джихад, если живы родители?', 'Автор подчёркивает исключительную важность прав родителей и приводит наставление служить им.\n\nSource: Иди, служи своим родителям. Твой джихад — рядом с ними.', 1, '["imported","akhlaq","test-4","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"рядом с родителями","answers":["рядом с родителями","в служении родителям","у родителей","служить родителям"],"required":["родител","служ"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Иди, служи своим родителям. Твой джихад — рядом с ними.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q17', 'Akhlaq', 'SHORT_TEXT', 'Какое состояние названо препятствием перед всяким благим делом?', 'Верующий не должен впадать в отчаяние, потому что опирается на милость и могущество Аллаха.\n\nSource: Отчаяние... является препятствием перед всяким благим делом.', 1, '["imported","akhlaq","test-4","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"отчаяние","answers":["отчаяние","безнадёжность","безнадежность"],"required":["отчая","безнадеж","безнадёж"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Отчаяние... является препятствием перед всяким благим делом.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q18', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: человек должен сохранять равновесие между страхом и ________.', 'Текст предупреждает и против отчаяния, и против полной самоуверенности, требуя равновесия хавфа и раджи.\n\nSource: сохраняя равновесие между страхом и надеждой.', 2, '["imported","akhlaq","test-4","fill_blank"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"надеждой","answers":["надеждой","надежда","раджой","раджа"],"required":["надеж","радж"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"сохраняя равновесие между страхом и надеждой.","sourceQuestionType":"fill_blank","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q19', 'Akhlaq', 'SHORT_TEXT', 'Какой термин означает слепую привязанность к своей мысли и упрямство вопреки разуму и духу религии?', 'Таассуб описан как поведение, построенное на чувствах и упрямом пренебрежении к истине.\n\nSource: таассуб означает слепую привязанность к чему-либо или к какой-либо мысли.', 2, '["imported","akhlaq","test-4","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"таассуб","answers":["таассуб","слепой фанатизм","фанатизм","узость"],"required":["таассуб","фанат"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"таассуб означает слепую привязанность к чему-либо или к какой-либо мысли.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q20', 'Akhlaq', 'SHORT_TEXT', 'Что должно быть в верующем вместо фанатизма, согласно тексту?', 'Религиозная стойкость означает верность предписаниям религии без грубости, узости и фанатизма.\n\nSource: в верующем бывает не фанатизм, а салабат-и диние.', 2, '["imported","akhlaq","test-4","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"салабат-и диние","answers":["салабат-и диние","религиозная стойкость","религиозная твёрдость","религиозная твердость"],"required":["стойк","салабат"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"в верующем бывает не фанатизм, а салабат-и диние.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q21', 'Akhlaq', 'SHORT_TEXT', 'Что в тексте названо малым или скрытым ширком?', 'Рия — совершение дел ради того, чтобы люди увидели, а не ради Аллаха.\n\nSource: На вопрос... «Что такое малый ширк?» — был дан ответ: «Рия».', 1, '["imported","akhlaq","test-4","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"рия","answers":["рия","показуха","показное благочестие","дела напоказ"],"required":["рия","показ"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"На вопрос... «Что такое малый ширк?» — был дан ответ: «Рия».","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q22', 'Akhlaq', 'SHORT_TEXT', 'Какое дурное свойство, наряду с несерьёзностью и пустым кривлянием, не имеет места на пути верующего?', 'Раздел призывает сделать серьёзность природой и противостоять пустой, бесполезной атмосфере.\n\nSource: развязности, несерьёзности и пустому кривлянию нет места в нашем пути.', 2, '["imported","akhlaq","test-4","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"развязность","answers":["развязность","несерьёзность","несерьезность","пустое кривляние","беспечность"],"required":["развяз","несерь"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"развязности, несерьёзности и пустому кривлянию нет места в нашем пути.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q23', 'Akhlaq', 'SHORT_TEXT', 'Как называется желание отомстить кому-либо?', 'Злоба возникает из неуправляемого гнева и ведёт человека к новым грехам.\n\nSource: Злоба — это желание отомстить кому-либо.', 1, '["imported","akhlaq","test-4","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"злоба","answers":["злоба","желание отомстить","мстительность","ненависть с желанием мести"],"required":["злоб","мест"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Злоба — это желание отомстить кому-либо.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q24', 'Akhlaq', 'SHORT_TEXT', 'Что, кроме разумности и истинности слов, особенно важно учитывать, чтобы критика была полезной?', 'Разрушительная критика ранит; полезная критика требует выверенного стиля, подходящего тона и учёта состояния собеседника.\n\nSource: важны не только разумность и истинность сказанных слов, но и то, каким образом они преподносятся.', 3, '["imported","akhlaq","test-4","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"стиль и способ преподнесения","answers":["стиль и способ преподнесения","метод и стиль","каким образом слова преподносятся","тон и стиль","манера изложения"],"required":["стиль","метод"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"важны не только разумность и истинность сказанных слов, но и то, каким образом они преподносятся.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_04_q25', 'Akhlaq', 'SHORT_TEXT', 'Каким поведением, согласно аяту, человек может сделать тщетными свои милостыни и благодеяния?', 'Добро следует совершать ради довольства Аллаха и забывать о нём, не ставя другого под бремя признательности.\n\nSource: Не делайте тщетными ваши милостыни и благодеяния, попрекая людей и причиняя им страдания!', 2, '["imported","akhlaq","test-4","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"попреканием и причинением страдания","answers":["попреканием","попреканием людей","причинением страдания","попреканием и причинением боли","напоминанием о благодеянии"],"required":["попрек","страдан"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Не делайте тщетными ваши милостыни и благодеяния, попрекая людей и причиняя им страдания!","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q01', 'Akhlaq', 'SHORT_TEXT', 'Как называется выискивание скрытых состояний, ошибок и грехов других людей?', 'Раздел прямо запрещает расследовать чужие грехи и сокровенные стороны людей.\n\nSource: 19. Таджассус [выискивание сокровенного в других]', 1, '["imported","akhlaq","test-5","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"таджассус","answers":["таджассус","выискивание сокровенного","выискивание чужих недостатков","выслеживание"],"required":["таджассус","выискив"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"19. Таджассус [выискивание сокровенного в других]","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q02', 'Akhlaq', 'TRUE_FALSE', 'Верно ли: в тексте сказано, что Аллах назначил людей прокурорами для расследования грехов других?', 'Автор говорит обратное: нет обязанности выискивать зло, а охота за чужими ошибками считается безнравственностью.\n\nSource: Аллах не назначал нас прокурорами, чтобы мы расследовали грехи других.', 1, '["imported","akhlaq","test-5","true_false"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"Неверно","answers":["неверно","нет","ложь","неправильно"],"required":["невер","нет"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Аллах не назначал нас прокурорами, чтобы мы расследовали грехи других.","sourceQuestionType":"true_false","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q03', 'Akhlaq', 'SHORT_TEXT', 'Чем, по тексту, нужно заняться вместо чужих недостатков и изъянов?', 'Текст переводит внимание от слежки за людьми к самоотчёту и исправлению себя.\n\nSource: повернуться к собственным недостаткам и заняться их исправлением.', 2, '["imported","akhlaq","test-5","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"собственными недостатками","answers":["собственными недостатками","исправлением своих недостатков","своими изъянами","самоисправлением","самоотчётом"],"required":["собствен","недостат"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"повернуться к собственным недостаткам и заняться их исправлением.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q04', 'Akhlaq', 'SHORT_TEXT', 'Как называется мысль, при которой человек считает себя выше других?', 'Автор показывает, что мысль о превосходстве питается самостью и может перейти в стремление властвовать над людьми.\n\nSource: Мысль о превосходстве означает, что человек считает себя выше других.', 1, '["imported","akhlaq","test-5","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"мысль о превосходстве","answers":["мысль о превосходстве","чувство превосходства","считать себя выше других","превозношение себя"],"required":["превосход"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Мысль о превосходстве означает, что человек считает себя выше других.","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q05', 'Akhlaq', 'SHORT_TEXT', 'К кому, согласно тексту, следует относить всякий дар, чтобы не впасть в неблагодарность и самость?', 'Дары должны вести к благодарности Аллаху; присваивание их себе превращает их в повод для гордыни.\n\nSource: всякий дар исходит от Аллаха.', 2, '["imported","akhlaq","test-5","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"к Аллаху","answers":["к Аллаху","Аллаху","к Всевышнему","к Истинному Дарителю"],"required":["Аллах","Дарител"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"всякий дар исходит от Аллаха.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q06', 'Akhlaq', 'SHORT_TEXT', 'От каких слов и поступков, согласно суре «Аль-Му’минун», сторонятся совершенные верующие?', 'Верующий не растрачивает жизнь на то, что не приносит пользы ни в этом мире, ни в будущей жизни.\n\nSource: Они сторонятся всяких бесполезных и бессмысленных слов и поступков.', 1, '["imported","akhlaq","test-5","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"от бесполезных и бессмысленных","answers":["от бесполезных и бессмысленных","от пустого и бесполезного","от бесполезных слов и поступков","от маляйани"],"required":["бесполез","пуст"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Они сторонятся всяких бесполезных и бессмысленных слов и поступков.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q07', 'Akhlaq', 'FILL_BLANK', 'Заполните пропуск: «Говори о Возлюбленной, иначе — ________!»', 'Это краткое правило связано с отказом от пустой речи и с направлением слова к поминанию Аллаха.\n\nSource: Говори о Возлюбленной, иначе — молчи!', 1, '["imported","akhlaq","test-5","fill_blank"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"молчи","answers":["молчи","молчать","храни молчание"],"required":["молч"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Говори о Возлюбленной, иначе — молчи!","sourceQuestionType":"fill_blank","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q08', 'Akhlaq', 'SHORT_TEXT', 'Что, по словам автора, поддерживает человека живым и удерживает от пустого и бесполезного?', 'Постоянное полезное служение создаёт благой круг и не оставляет пустот для бесполезного.\n\nSource: Служение — наша жизнь.', 2, '["imported","akhlaq","test-5","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"служение","answers":["служение","служение вере и Корану","обязанность служения","служение на пути Аллаха"],"required":["служ"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Служение — наша жизнь.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q09', 'Akhlaq', 'SHORT_TEXT', 'Как называется болезнь сердца, при которой человек хочет, чтобы его постоянно хвалили?', 'Любовь к похвале описана как болезнь, разрушающая внутренний мир и духовные способности человека.\n\nSource: любовь к похвале и желание... быть восхваляемым.', 1, '["imported","akhlaq","test-5","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"страсть к похвале","answers":["страсть к похвале","любовь к похвале","желание быть восхваляемым","жажда похвалы"],"required":["похвал","восхвал"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"любовь к похвале и желание... быть восхваляемым.","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q10', 'Akhlaq', 'SHORT_TEXT', 'Какой максимальный срок обиды на брата-мусульманина назван в хадисе?', 'Хадис ограничивает обиду, чтобы отчуждение не разрушало братство и общественную связь.\n\nSource: не дозволено держать обиду на своего брата более трёх дней.', 1, '["imported","akhlaq","test-5","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"три дня","answers":["три дня","3 дня","не более трёх дней","не более трех дней"],"required":["три","3"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"не дозволено держать обиду на своего брата более трёх дней.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q11', 'Akhlaq', 'SHORT_TEXT', 'О каком будущем прежде всего должен тревожиться верующий, согласно разделу о тревоге о будущем?', 'Тревога о будущем должна направлять человека к подготовке к вечной жизни, а не только к земным расчётам.\n\nSource: Будущее, о котором больше всего следует думать... — это будущее Ахирета.', 2, '["imported","akhlaq","test-5","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"о будущем Ахирета","answers":["о будущем Ахирета","об Ахирете","о загробной жизни","о вечной жизни","о будущей жизни"],"required":["Ахир","загроб","вечн"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Будущее, о котором больше всего следует думать... — это будущее Ахирета.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q12', 'Akhlaq', 'SHORT_TEXT', 'Какой термин означает привязаться к миру так, словно человек никогда не умрёт?', 'Тул-и эмель заставляет забыть Ахирет и жить бесконечными земными ожиданиями.\n\nSource: Тул-и эмель означает привязаться к миру так, словно человек никогда не умрёт.', 1, '["imported","akhlaq","test-5","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"тул-и эмель","answers":["тул-и эмель","долгая надежда","долгие надежды","привязанность к земным ожиданиям"],"required":["тул","эмель","долг"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Тул-и эмель означает привязаться к миру так, словно человек никогда не умрёт.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q13', 'Akhlaq', 'SHORT_TEXT', 'Какое средство названо одним из путей преодоления иллюзии вечности?', 'Память о смерти пробивает иллюзию вечного пребывания в мире и помогает сохранить искренность.\n\nSource: Один из путей преодоления иллюзии вечности — рабита-и мевт.', 2, '["imported","akhlaq","test-5","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"рабита-и мевт","answers":["рабита-и мевт","рабита смерти","памятование о смерти","частое размышление о смерти"],"required":["смерт","рабита"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Один из путей преодоления иллюзии вечности — рабита-и мевт.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q14', 'Akhlaq', 'SHORT_TEXT', 'Как называется человек, который чрезмерно замыкается в доме, отрывается от общества и предаёт волю удобству?', 'Домопоклонничество критикуется не как забота о семье, а как бегство от общественных обязанностей и трудностей служения.\n\nSource: Домопоклонник — это человек, чрезмерно привязанный к своему дому.', 2, '["imported","akhlaq","test-5","term_definition"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"домопоклонник","answers":["домопоклонник","человек, чрезмерно привязанный к дому","замкнувшийся в доме","домосед из-за удобства"],"required":["дом","удоб"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Домопоклонник — это человек, чрезмерно привязанный к своему дому.","sourceQuestionType":"term_definition","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q15', 'Akhlaq', 'SHORT_TEXT', 'Как в тексте оценивается желание при всяком случае заявлять о себе?', 'Желание самовыражения связывается с высокомерием и уджбом; лечение — смирение и осознание рабства перед Аллахом.\n\nSource: Желание при всяком случае заявлять о себе — это духовный недуг.', 2, '["imported","akhlaq","test-5","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"духовный недуг","answers":["духовный недуг","болезнь","предосудительное желание","недуг самовыражения"],"required":["недуг","болез"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Желание при всяком случае заявлять о себе — это духовный недуг.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q16', 'Akhlaq', 'SHORT_TEXT', 'Как называются опасные места на пути служения, где могут поскользнуться ноги идущих?', 'Четвёртая глава посвящена именно таким точкам скольжения, где духовная жизнь может получить рану.\n\nSource: эти скользкие места мы называем мезелле-и акдам.', 1, '["imported","akhlaq","test-5","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"мезелле-и акдам","answers":["мезелле-и акдам","точки скольжения","места скольжения","скользкие места"],"required":["скольж","мезелле"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"эти скользкие места мы называем мезелле-и акдам.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q17', 'Akhlaq', 'SHORT_TEXT', 'Назовите одну из шести сатанинских ловушек, перечисленных в «Худжумат-и ситте».', 'В «Шести нападениях» перечислены главные духовные ловушки: положение, страх, алчность, расизм, самость и телесный покой.\n\nSource: в капканы вроде любви к положению, страха, алчности, расизма, самости.', 2, '["imported","akhlaq","test-5","short_answer"]', NULL, 'REGEX', '{"caseSensitive":false,"answer":"любовь к положению","answers":["любовь к положению","страх","алчность","расизм","самость","пристрастие к телесному покою","хубб-и джах","эгоизм"],"required":[],"forbidden":[],"pattern":"(полож|страх|алчн|расизм|самост|эгоизм|поко|джах)","flags":"iu","sourceQuote":"в капканы вроде любви к положению, страха, алчности, расизма, самости.","sourceQuestionType":"short_answer","sourceGradingMode":"regex"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q18', 'Akhlaq', 'SHORT_TEXT', 'Какой термин означает любовь к положению, страсть к званию и пристрастие к славе?', 'Хубб-и джах описан как слабая жила человека, связанная с должностью, славой, признанием и похвалой.\n\nSource: выражение «хубб-и джах»... любовь к положению, страсть к званию.', 1, '["imported","akhlaq","test-5","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"хубб-и джах","answers":["хубб-и джах","любовь к положению","пристрастие к славе","страсть к званию","жажда ранга"],"required":["джах","полож","слав"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"выражение «хубб-и джах»... любовь к положению, страсть к званию.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q19', 'Akhlaq', 'TRUE_FALSE', 'Верно ли: в тексте должность для зрелого человека является целью сама по себе, а не средством служения?', 'Правильное отношение к должности — видеть в ней средство служения и путь к довольству Аллаха, а не самостоятельную цель.\n\nSource: должность — лишь средство, вспомогательный инструмент для служения.', 2, '["imported","akhlaq","test-5","true_false"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"Неверно","answers":["неверно","нет","ложь","неправильно"],"required":["невер","нет"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"должность — лишь средство, вспомогательный инструмент для служения.","sourceQuestionType":"true_false","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q20', 'Akhlaq', 'SHORT_TEXT', 'Кого, согласно аяту в разделе о страхе, следует бояться истинно верующим?', 'Страх должен быть направлен к Аллаху и будущей жизни, а не рассеиваться на мирские угрозы.\n\nSource: Если вы истинно верующие, не бойтесь их, бойтесь Меня.', 2, '["imported","akhlaq","test-5","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"Аллаха","answers":["Аллаха","Всевышнего","Меня","только Аллаха"],"required":["Аллах","Всевыш"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Если вы истинно верующие, не бойтесь их, бойтесь Меня.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q21', 'Akhlaq', 'SHORT_TEXT', 'Какой термин означает неумеренную страсть к обладанию, жадность и ненасытное стремление?', 'Хырс представлен как качество, способное привести к духовным и материальным потерям.\n\nSource: Хырс означает алчность, желание чего-либо с ненасытным вожделением.', 1, '["imported","akhlaq","test-5","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"хырс","answers":["хырс","алчность","неумеренная страсть к обладанию","жадность","ненасытность"],"required":["хырс","алч","жад"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Хырс означает алчность, желание чего-либо с ненасытным вожделением.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q22', 'Akhlaq', 'SHORT_TEXT', 'Что названо противоядием от страстного вожделения и алчности?', 'Довольство малым направляет чувство желания к добру и удерживает от погружения в мирские притязания.\n\nSource: Противоядие от страстного вожделения: довольство малым.', 2, '["imported","akhlaq","test-5","short_answer"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"довольство малым","answers":["довольство малым","каноат","жить экономно","умеренность","довольствоваться необходимым"],"required":["доволь","малым"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Противоядие от страстного вожделения: довольство малым.","sourceQuestionType":"short_answer","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q23', 'Akhlaq', 'SHORT_TEXT', 'Какой национализм, согласно тексту, отвергает Ислам?', 'Текст отличает положительное национальное чувство от расизма, который исключает другие народы и ставит расу выше религии.\n\nSource: Ислам против такого понимания национализма, которое ставит расовую принадлежность выше религии.', 2, '["imported","akhlaq","test-5","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"отрицательный национализм, ставящий расу выше религии","answers":["отрицательный национализм","расизм","национализм, ставящий расу выше религии","расовую принадлежность выше религии"],"required":["рас","религ"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Ислам против такого понимания национализма, которое ставит расовую принадлежность выше религии.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q24', 'Akhlaq', 'SHORT_TEXT', 'Какой термин обозначает духовную болезнь привязанности к самому себе и рассмотрения дел через личную выгоду?', 'Энанийет заставляет человека ставить своё «я» в центр и подчинять дела личным выгодам.\n\nSource: Энанийет... это название духовной болезни.', 2, '["imported","akhlaq","test-5","term_definition"]', NULL, 'ACCEPTED_ANSWERS', '{"caseSensitive":false,"answer":"энанийет","answers":["энанийет","эгоизм","самость","себялюбие","эгоцентризм"],"required":["энаний","эго"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Энанийет... это название духовной болезни.","sourceQuestionType":"term_definition","sourceGradingMode":"accepted_answers"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)),
  ('seed_test_05_q25', 'Akhlaq', 'SHORT_TEXT', 'Какую истину Бадиуззаман предлагает противопоставить склонности к покою и лености?', 'Средство от лености — подняться усилием воли, трудиться и связывать успехи с Аллахом, а не с собой.\n\nSource: Человеку принадлежит лишь то, к чему он приложил усилие.', 2, '["imported","akhlaq","test-5","short_answer"]', NULL, 'KEYWORDS', '{"caseSensitive":false,"answer":"человеку принадлежит лишь то, к чему он приложил усилие","answers":["человеку принадлежит лишь то, к чему он приложил усилие","нет для человека ничего, кроме того, над чем он трудился","истина усилия","труд и усилие"],"required":["усил","труд"],"forbidden":[],"pattern":"","flags":"","sourceQuote":"Человеку принадлежит лишь то, к чему он приложил усилие.","sourceQuestionType":"short_answer","sourceGradingMode":"keywords"}', CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3))
